export type BlogPost = {
  id: number;
  title: string;
  excerpt: string;
  href: string;
  date: string;
  image?: string;
};

type WordPressPost = {
  id: number;
  date: string;
  link: string;
  title?: { rendered?: string };
  excerpt?: { rendered?: string };
  _embedded?: {
    "wp:featuredmedia"?: Array<{
      source_url?: string;
    }>;
  };
};

const fallbackPosts: BlogPost[] = [
  {
    id: 1,
    title: "How to Prepare Old Photos for Scanning",
    excerpt:
      "Simple steps to sort, clean, and protect family photos before digitization.",
    href: "https://scanjunction.com/blog/",
    date: "ScanJunction"
  },
  {
    id: 2,
    title: "Why Families Digitize Albums and VHS Tapes",
    excerpt:
      "A practical look at preserving fragile memories before age and humidity take over.",
    href: "https://scanjunction.com/blog/",
    date: "ScanJunction"
  },
  {
    id: 3,
    title: "Archival Storage Tips for Digital Memories",
    excerpt:
      "Keep your restored memories organized, searchable, and safely backed up.",
    href: "https://scanjunction.com/blog/",
    date: "ScanJunction"
  }
];

const stripHtml = (value = "") =>
  value
    .replace(/<[^>]*>/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const decodeEntities = (value = "") =>
  value
    .replace(/&#8217;/g, "'")
    .replace(/&#8216;/g, "'")
    .replace(/&#8220;/g, '"')
    .replace(/&#8221;/g, '"')
    .replace(/&#038;/g, "&")
    .replace(/&amp;/g, "&")
    .replace(/&nbsp;/g, " ");

export async function getLatestPosts(): Promise<BlogPost[]> {
  try {
    const response = await fetch(
      "https://scanjunction.com/wp-json/wp/v2/posts?per_page=3&_embed=1",
      {
        next: { revalidate: 3600 }
      }
    );

    if (!response.ok) {
      return fallbackPosts;
    }

    const posts = (await response.json()) as WordPressPost[];

    if (!Array.isArray(posts) || posts.length === 0) {
      return fallbackPosts;
    }

    return posts.map((post) => ({
      id: post.id,
      title: decodeEntities(stripHtml(post.title?.rendered)),
      excerpt: decodeEntities(stripHtml(post.excerpt?.rendered)).slice(0, 150),
      href: post.link,
      date: new Intl.DateTimeFormat("en-IN", {
        month: "short",
        day: "numeric",
        year: "numeric"
      }).format(new Date(post.date)),
      image: post._embedded?.["wp:featuredmedia"]?.[0]?.source_url
    }));
  } catch {
    return fallbackPosts;
  }
}
